assign tim_ck_out = USE_PLL != "TRUE" ? clk : (PLLFRQ[5:4] == 2'b00 ? clk : (PLLFRQ[5:4] == 2'b01 ? pll_clk_out_int : (PLLFRQ[5:4] == 2'b11 ? tim_div_cnt[1] : tim_div_cnt[0])));
assign pll_enabled = USE_PLL != "TRUE" ? 1'b0 : (|PLLFRQ[5:4]);

endmodule

