reg [15:0]t_ovf_value;
always @*
begin
    case({TCCRB[`WGM03:`WGM02], TCCRA[`WGM01:`WGM00]})
        4'd5, 4'd6, 4'd7, 4'd14, 4'd15: t_ovf_value = top_value;
        4'd0, 4'd4, 4'd12: t_ovf_value = 16'hFFFF;
