end

// Read registers.
always @*
begin
    if(rst)
    begin
        bus_io_out = 8'h00;
        bus_dat_out = 8'h00;
    end
    else
    begin
        bus_io_out = 8'h00;
        bus_dat_out = 8'h00;
        if(rd_io)
        begin
            case(addr_io)
                GTCCR_ADDR:
                begin
                    if(GTCCR_ADDR < 'h40)
                        bus_io_out = GTCCR;
                end
                TCCRA_ADDR:
                begin
                    if(TCCRA_ADDR < 'h40)
                        bus_io_out = TCCRA;
                end
                TCCRB_ADDR:
                begin
                    if(TCCRB_ADDR < 'h40)
                        bus_io_out = TCCRB;
                end
                TCCRC_ADDR:
                begin
                    if(TCCRC_ADDR < 'h40)
                        bus_io_out = TCCRC;
                end
                TCCRD_ADDR:
                begin
                    if(TCCRD_ADDR < 'h40)
                        bus_io_out = TCCRD;
                end
                TCNTL_ADDR:
                begin
                    if(TCNTL_ADDR < 'h40)
                        bus_io_out = TCNTL;
                end
                TCNTH_ADDR:
                begin
                    if(TCNTH_ADDR < 'h40)
                        bus_io_out = TMP_REG;
                end
                ICRL_ADDR:
                begin
                    if(ICRL_ADDR < 'h40)
                        bus_io_out = ICRL;
                end
                ICRH_ADDR:
                begin
                    if(ICRH_ADDR < 'h40)
                        bus_io_out = TMP_REG;
                end
                OCRAL_ADDR:
                begin
                    if(OCRAL_ADDR < 'h40)
                        bus_io_out = OCRAL;
                end
                OCRAH_ADDR:
                begin
                    if(OCRAH_ADDR < 'h40)
                        bus_io_out = OCRAH;
                end
                OCRBL_ADDR:
                begin
                    if(OCRBL_ADDR < 'h40 && USE_OCRB == "TRUE")
                        bus_io_out = OCRBL;
                end
                OCRBH_ADDR:
                begin
                    if(OCRBH_ADDR < 'h40 && USE_OCRB == "TRUE")
                        bus_io_out = OCRBH;
                end
                OCRCL_ADDR:
                begin
                    if(OCRCL_ADDR < 'h40 && USE_OCRC == "TRUE")
                        bus_io_out = OCRCL;
                end
                OCRCH_ADDR:
                begin
                    if(OCRCH_ADDR < 'h40 && USE_OCRC == "TRUE")
                        bus_io_out = OCRCH;
                end
                OCRDL_ADDR:
                begin
                    if(OCRDL_ADDR < 'h40 && USE_OCRD == "TRUE")
                        bus_io_out = OCRDL;
                end
                OCRDH_ADDR:
                begin
                    if(OCRDH_ADDR < 'h40 && USE_OCRD == "TRUE")
                        bus_io_out = OCRDH;
                end
                TIFR_ADDR:
                begin
                    if(TIFR_ADDR < 'h40)
                        bus_io_out = TIFR;
                end
                TIMSK_ADDR:
                begin
                    if(TIMSK_ADDR < 'h40)
                        bus_io_out = TIMSK;
                end
                default: bus_io_out = 8'h00;
            endcase
        end
        if(rd_dat)
        begin
            case(addr_dat)
                GTCCR_ADDR:
                begin
                    if(GTCCR_ADDR >= 'h40)
                        bus_dat_out = GTCCR;
                end
                TCCRA_ADDR:
                begin
                    if(TCCRA_ADDR >= 'h40)
                        bus_dat_out = TCCRA;
                end
                TCCRB_ADDR:
                begin
                    if(TCCRB_ADDR >= 'h40)
                        bus_dat_out = TCCRB;
                end
                TCCRC_ADDR:
                begin
                    if(TCCRC_ADDR >= 'h40)
                        bus_dat_out = TCCRC;
                end
                TCCRD_ADDR:
                begin
                    if(TCCRD_ADDR >= 'h40)
                        bus_dat_out = TCCRD;
                end
                TCNTL_ADDR:
                begin
                    if(TCNTL_ADDR >= 'h40)
                        bus_dat_out = TCNTL;
                end
                TCNTH_ADDR:
                begin
                    if(TCNTH_ADDR >= 'h40)
                        bus_dat_out = TMP_REG;
                end
                ICRL_ADDR:
                begin
                    if(ICRL_ADDR >= 'h40)
                        bus_dat_out = ICRL;
                end
                ICRH_ADDR:
                begin
                    if(ICRH_ADDR >= 'h40)
                        bus_dat_out = TMP_REG;
                end
                OCRAL_ADDR:
                begin
                    if(OCRAL_ADDR >= 'h40)
                        bus_dat_out = OCRAL;
                end
                OCRAH_ADDR:
                begin
                    if(OCRAH_ADDR >= 'h40)
                        bus_dat_out = OCRAH;
                end
                OCRBL_ADDR:
                begin
                    if(OCRBL_ADDR >= 'h40 && USE_OCRB == "TRUE")
                        bus_dat_out = OCRBL;
                end
                OCRBH_ADDR:
                begin
                    if(OCRBH_ADDR >= 'h40 && USE_OCRB == "TRUE")
                        bus_dat_out = OCRBH;
                end
                OCRCL_ADDR:
                begin
                    if(OCRCL_ADDR >= 'h40 && USE_OCRC == "TRUE")
                        bus_dat_out = OCRCL;
                end
                OCRCH_ADDR:
                begin
                    if(OCRCH_ADDR >= 'h40 && USE_OCRC == "TRUE")
                        bus_dat_out = OCRCH;
                end
                OCRDL_ADDR:
                begin
                    if(OCRDL_ADDR >= 'h40 && USE_OCRD == "TRUE")
                        bus_dat_out = OCRDL;
                end
                OCRDH_ADDR:
                begin
                    if(OCRDH_ADDR >= 'h40 && USE_OCRD == "TRUE")
                        bus_dat_out = OCRDH;
                end
