				end
				OCRDH_ADDR:
				begin
					if(OCRDH_ADDR >= 'h40 && USE_OCRD == "TRUE")
						bus_dat_out = OCRDH;
				end
				TIFR_ADDR:
				begin
					if(TIFR_ADDR >= 'h40)
						bus_dat_out = TIFR;
				end
				TIMSK_ADDR:
				begin
					if(TIMSK_ADDR >= 'h40)
						bus_dat_out = TIMSK;
				end
			endcase
		end
	end
end

/* Set "oc" pin on specified conditions*/
always @ (posedge clk)
begin
	if(rst)
	begin
		TMP_REG_rd <= 8'h00;
		TMP_REG_wr <= 8'h00;
		GTCCR <= 8'h00;
		TCCRA <= 8'h00;
		TCCRB <= 8'h00;
		TCCRC <= 8'h00;
		TCCRD <= 8'h00;
		TCNTL <= 8'h00;
		TCNTH <= 8'h00;
		OCRAL <= 8'h00;
		OCRAH <= 8'h00;
		OCRBL <= 8'h00;
		OCRBH <= 8'h00;
		OCRCL <= 8'h00;
		OCRCH <= 8'h00;
		OCRDL <= 8'h00;
		OCRDH <= 8'h00;
		ICRL <= 8'h00;
		ICRH <= 8'h00;
		OCRA_int <= 16'h0000;
		OCRB_int <= 16'h0000;
		OCRC_int <= 16'h0000;
		OCRD_int <= 16'h0000;
		TIMSK <= 8'h00;
		TIFR <= 8'h00;
		tov_p <= 1'b0;
		tov_n <= 1'b0;
		ocra_p <= 1'b0;
		ocra_n <= 1'b0;
		ocrb_p <= 1'b0;
		ocrb_n <= 1'b0;
		ocrc_p <= 1'b0;
		ocrc_n <= 1'b0;
		ocrd_p <= 1'b0;
		ocrd_n <= 1'b0;
		oca <= 1'b0;
		ocb <= 1'b0;
		occ <= 1'b0;
		ocd <= 1'b0;
		up_count <= 1'b1;
		clk_int_del <= 1'b0;
	end
	else
	begin
		if(tov_p ^ tov_n)
		begin
			TIFR[`TOV0] <= 1'b1;
			tov_n <= tov_p;
		end	
		if(ocra_p ^ ocra_n)
		begin
			TIFR[`OCF0A] <= 1'b1;
			ocra_n <= ocra_p;
		end	
		if(ocrb_p ^ ocrb_n)
		begin
			TIFR[`OCF0B] <= 1'b1;
			ocrb_n <= ocrb_p;
		end
		if(ocrc_p ^ ocrc_n)
		begin
			TIFR[`OCF0C] <= 1'b1;
			ocrc_n <= ocrc_p;
		end
		if(ocrd_p ^ ocrd_n)
		begin
			TIFR[`OCF0D] <= 1'b1;
			ocrd_n <= ocrd_p;
		end
		if(tov_int_rst)
		begin
			TIFR[`TOV0] <= 1'b0;
		end
		if(ocra_int_rst)
		begin
			TIFR[`OCF0A] <= 1'b0;
		end
		if(ocrb_int_rst)
		begin
			TIFR[`OCF0B] <= 1'b0;
		end
		if(ocrc_int_rst)
		begin
			TIFR[`OCF0C] <= 1'b0;
		end
		if(ocrd_int_rst)
		begin
			TIFR[`OCF0D] <= 1'b0;
		end
		// Sample one IO core clock once every prescaller positive edge clock.
		clk_int_del <= clk_int; // Shift prescaller clock to a delay register every IO core positive edge clock to detect prescaller positive edges.
		if(((~clk_int_del & clk_int) || TCCRB[`CS02:`CS00] == 3'b001) && TCCRB[`CS02:`CS00] != 3'b000) // if prescaller clock = IO core clock disable prescaller positive edge detector.
		begin
			if(up_count)
			begin
				{TCNTH, TCNTL} <= {TCNTH, TCNTL} + 16'd1;
			end
			else
			begin
				{TCNTH, TCNTL} <= {TCNTH, TCNTL} - 16'd1;
			end
			// OCRA
			if(updt_ocr_on_top ? ({TCNTH, TCNTL} == top_value) : (updt_ocr_on_bottom ? ({TCNTH, TCNTL} == 10'h000) : ({TCNTH, TCNTL} == OCRA_int)))
			begin
				OCRA_int <= {OCRAH, OCRAL};
			end			
			if({TCNTH, TCNTL} == OCRA_int)
			begin
				case({TCCRB[`WGM03:`WGM02], TCCRA[`WGM01:`WGM00]})
					4'd4, 4'd12: oca <= ~oca;
					default:
					begin
						case(OCRA_int)
							16'h0000:	oca <= 1'b0;
							16'hFFFF:	oca <= 1'b1;
							default:
							begin
								if(up_count)
								begin
									case(TCCRA[`COM0A1:`COM0A0])
										2'h1: oca <= ~oca;
										2'h2: oca <= 1'b0;
										2'h3: oca <= 1'b1;
									endcase
								end
								else
								begin
									case(TCCRA[`COM0A1:`COM0A0])
										2'h1: oca <= ~oca;
										2'h2: oca <= 1'b1;
										2'h3: oca <= 1'b0;
									endcase
								end
							end
						endcase
					end
				endcase
				if(TIMSK[`OCIE0A] == 1'b1)
				begin
					if(ocra_p == ocra_n && clk_active == 1'b1)
					begin
						ocra_p <= ~ocra_p;
					end
				end
				else
				begin
					ocra_p <= 1'b0;
					ocra_n <= 1'b0;
				end
			end
			// !OCRA
			if(USE_OCRB == "TRUE")
			begin
				// OCRB
				if(updt_ocr_on_top ? ({TCNTH, TCNTL} == top_value) : (updt_ocr_on_bottom ? ({TCNTH, TCNTL} == 10'h000) : ({TCNTH, TCNTL} == OCRB_int)))
				begin
					OCRB_int <= {OCRBH, OCRBL};
				end			
				if({TCNTH, TCNTL} == OCRB_int)
				begin
					case({TCCRB[`WGM03:`WGM02], TCCRA[`WGM01:`WGM00]})
						4'd4, 4'd12: ocb <= ~ocb;
						default:
						begin
							case(OCRB_int)
								16'h0000:	ocb <= 1'b0;
								16'hFFFF:	ocb <= 1'b1;
								default:
								begin
									if(up_count)
									begin
										case(TCCRA[`COM0B1:`COM0B0])
											2'h1: ocb <= ~ocb;
											2'h2: ocb <= 1'b0;
											2'h3: ocb <= 1'b1;
										endcase
									end
									else
									begin
										case(TCCRA[`COM0B1:`COM0B0])
											2'h1: ocb <= ~ocb;
											2'h2: ocb <= 1'b1;
											2'h3: ocb <= 1'b0;
										endcase
									end
								end
							endcase
						end
					endcase
					if(TIMSK[`OCIE0B] == 1'b1)
					begin
						if(ocrb_p == ocrb_n && clk_active == 1'b1)
						begin
							ocrb_p <= ~ocrb_p;
						end
					end
					else
					begin
						ocrb_p <= 1'b0;
						ocrb_n <= 1'b0;
					end
				end
			end // USE_OCRB != "TRUE"
			if(USE_OCRC == "TRUE")
			begin
				// OCRB
				if(updt_ocr_on_top ? ({TCNTH, TCNTL} == top_value) : (updt_ocr_on_bottom ? ({TCNTH, TCNTL} == 10'h000) : ({TCNTH, TCNTL} == OCRC_int)))
				begin
					OCRC_int <= {OCRCH, OCRCL};
				end			
				if({TCNTH, TCNTL} == OCRC_int)
				begin
					case({TCCRB[`WGM03:`WGM02], TCCRA[`WGM01:`WGM00]})
						4'd4, 4'd12: occ <= ~occ;
						default:
						begin
							case(OCRC_int)
								16'h0000:	occ <= 1'b0;
								16'hFFFF:	occ <= 1'b1;
								default:
								begin
									if(up_count)
									begin
										case(TCCRA[`COM0C1:`COM0C0])
											2'h1: occ <= ~occ;
											2'h2: occ <= 1'b0;
											2'h3: occ <= 1'b1;
										endcase
									end
									else
									begin
										case(TCCRA[`COM0C1:`COM0C0])
											2'h1: occ <= ~occ;
											2'h2: occ <= 1'b1;
											2'h3: occ <= 1'b0;
										endcase
									end
								end
							endcase
						end
					endcase
					if(TIMSK[`OCIE0C] == 1'b1)
					begin
						if(ocrc_p == ocrc_n && clk_active == 1'b1)
						begin
							ocrc_p <= ~ocrc_p;
						end
					end
					else
					begin
						ocrc_p <= 1'b0;
						ocrc_n <= 1'b0;
					end
				end
			end // USE_OCRC != "TRUE"
			if(USE_OCRD == "TRUE")
			begin
				// OCRB
				if(updt_ocr_on_top ? ({TCNTH, TCNTL} == top_value) : (updt_ocr_on_bottom ? ({TCNTH, TCNTL} == 10'h000) : ({TCNTH, TCNTL} == OCRD_int)))
				begin
					OCRD_int <= {OCRDH, OCRDL};
				end			
				if({TCNTH, TCNTL} == OCRD_int)
				begin
					case({TCCRB[`WGM03:`WGM02], TCCRA[`WGM01:`WGM00]})
						4'd4, 4'd12: ocd <= ~ocd;
						default:
						begin
							case(OCRB_int)
								16'h0000:	ocd <= 1'b0;
								16'hFFFF:	ocd <= 1'b1;
								default:
								begin
									if(up_count)
									begin
										case(TCCRA[`COM0D1:`COM0D0])
											2'h1: ocd <= ~ocd;
											2'h2: ocd <= 1'b0;
											2'h3: ocd <= 1'b1;
										endcase
									end
									else
									begin
										case(TCCRA[`COM0D1:`COM0D0])
											2'h1: ocd <= ~ocd;
											2'h2: ocd <= 1'b1;
											2'h3: ocd <= 1'b0;
										endcase
									end
								end
							endcase
						end
					endcase
					if(TIMSK[`OCIE0D] == 1'b1)
					begin
						if(ocrd_p == ocrd_n && clk_active == 1'b1)
						begin
							ocrd_p <= ~ocrd_p;
						end
					end
					else
					begin
						ocrd_p <= 1'b0;
						ocrd_n <= 1'b0;
					end
				end
			end // USE_OCRD != "TRUE"
			// TCNT overflow logick.
			if({TCNTH, TCNTL} == t_ovf_value)
			begin
				if(TIMSK[`TOIE0] == 1'b1)
				begin
					if(tov_p == tov_n && clk_active == 1'b1)
					begin
						tov_p <= ~tov_p;
					end
				end
				else
				begin
					tov_p <= 1'b0;
					tov_n <= 1'b0;
				end
			end
			if({TCNTH, TCNTL} == top_value)
			begin
				case({TCCRB[`WGM03:`WGM02], TCCRA[`WGM01:`WGM00]})
					4'd1, 4'd2, 4'd3, 4'd8, 4'd9, 4'd10, 4'd11:
					begin
						up_count <= 1'b0;
						{TCNTH, TCNTL} <= {TCNTH, TCNTL} - 16'd1;
					end 
					default: {TCNTH, TCNTL} <= 16'h0000;
				endcase
			end
			else if({TCNTH, TCNTL} == 16'h0000)
			begin
				case({TCCRB[`WGM03:`WGM02], TCCRA[`WGM01:`WGM00]})
					4'd1, 4'd2, 4'd3, 4'd8, 4'd9, 4'd10, 4'd11: 
					begin
						up_count <= 1'b1;
						{TCNTH, TCNTL} <= {TCNTH, TCNTL} + 16'd1;
					end 
				endcase
			end
		end
		// Write registers
		if(wr_io)
		begin
			case(addr_io)
				GTCCR_ADDR:
				begin
					if(GTCCR_ADDR < 'h40)
						GTCCR <= bus_io_in;
				end
				TCCRA_ADDR:
				begin
					if(TCCRA_ADDR < 'h40)
						TCCRA <= bus_io_in;
				end
				TCCRB_ADDR:
				begin
					if(TCCRB_ADDR < 'h40)
						TCCRB <= bus_io_in;
				end
				TCCRC_ADDR:
				begin
					if(TCCRC_ADDR < 'h40)
						TCCRC <= bus_io_in;
				end
				TCCRD_ADDR:
				begin
					if(TCCRD_ADDR < 'h40)
						TCCRD <= bus_io_in;
				end
				TCNTL_ADDR:
				begin
					if(TCNTL_ADDR < 'h40)
					begin
						TCNTL <= bus_io_in;
						TCNTH <= TMP_REG_wr;
					end
				end
				ICRL_ADDR:
				begin
					if(ICRL_ADDR < 'h40)
					begin
						ICRL <= bus_io_in;
						ICRH <= TMP_REG_wr;
					end
				end
				OCRAL_ADDR:
				begin
					if(OCRAL_ADDR < 'h40)
						OCRAL <= bus_io_in;
						OCRAH <= TMP_REG_wr;
				end
				OCRBL_ADDR:
				begin
					if(OCRBL_ADDR < 'h40 && USE_OCRB == "TRUE")
					begin
						OCRBL <= bus_io_in;
						OCRBH <= TMP_REG_wr;
					end
				end
				OCRCL_ADDR:
				begin
					if(OCRCL_ADDR < 'h40 && USE_OCRC == "TRUE")
					begin
						OCRCL <= bus_io_in;
						OCRCH <= TMP_REG_wr;
					end
				end
				OCRDL_ADDR:
				begin
					if(OCRDL_ADDR < 'h40 && USE_OCRD == "TRUE")
					begin
						OCRDL <= bus_io_in;
						OCRDH <= TMP_REG_wr;
					end
				end
				TIFR_ADDR:
				begin
					if(TIFR_ADDR < 'h40)
						TIFR <= TIFR & ~bus_io_in;
				end
				TIMSK_ADDR:
				begin
					if(TIMSK_ADDR < 'h40)
						TIMSK <= bus_io_in;
				end
				TCNTH_ADDR, ICRH_ADDR, OCRAH_ADDR, OCRBH_ADDR, OCRCH_ADDR, OCRDH_ADDR:
				begin
					TMP_REG_wr <= bus_io_in;
				end
			endcase
		end
		if(wr_dat)
		begin
			case(addr_dat)
				GTCCR_ADDR:
				begin
					if(GTCCR_ADDR >= 'h40)
						GTCCR <= bus_dat_in;
				end
				TCCRA_ADDR:
				begin
					if(TCCRA_ADDR >= 'h40)
						TCCRA <= bus_dat_in;
				end
				TCCRB_ADDR:
				begin
					if(TCCRB_ADDR >= 'h40)
						TCCRB <= bus_dat_in;
				end
				TCCRC_ADDR:
				begin
					if(TCCRC_ADDR >= 'h40)
						TCCRC <= bus_dat_in;
				end
				TCCRD_ADDR:
				begin
					if(TCCRD_ADDR >= 'h40)
						TCCRD <= bus_dat_in;
				end
				TCNTL_ADDR:
				begin
					if(TCNTL_ADDR >= 'h40)
					begin
						TCNTL <= bus_dat_in;
						TCNTH <= TMP_REG_wr;
					end
				end
				ICRL_ADDR:
				begin
					if(ICRL_ADDR >= 'h40)
					begin
						ICRL <= bus_dat_in;
						ICRH <= TMP_REG_wr;
					end
				end
				OCRAL_ADDR:
				begin
					if(OCRAL_ADDR >= 'h40)
						OCRAL <= bus_dat_in;
						OCRAH <= TMP_REG_wr;
				end
				OCRBL_ADDR:
				begin
					if(OCRBL_ADDR >= 'h40 && USE_OCRB == "TRUE")
					begin
						OCRBL <= bus_dat_in;
						OCRBH <= TMP_REG_wr;
					end
				end
				OCRCL_ADDR:
				begin
					if(OCRCL_ADDR >= 'h40 && USE_OCRC == "TRUE")
					begin
						OCRCL <= bus_dat_in;
						OCRCH <= TMP_REG_wr;
					end
				end
				OCRDL_ADDR:
				begin
					if(OCRDL_ADDR >= 'h40 && USE_OCRD == "TRUE")
					begin
						OCRDL <= bus_dat_in;
						OCRDH <= TMP_REG_wr;
					end
				end
				TIFR_ADDR:
				begin
					if(TIFR_ADDR >= 'h40)
						TIFR <= TIFR & ~bus_dat_in;
				end
				TIMSK_ADDR:
				begin
					if(TIMSK_ADDR >= 'h40)
						TIMSK <= bus_dat_in;
				end
				TCNTH_ADDR, ICRH_ADDR, OCRAH_ADDR, OCRBH_ADDR, OCRCH_ADDR, OCRDH_ADDR:
				begin
					TMP_REG_wr <= bus_dat_in;
				end
			endcase
		end
		if(rd_io)
		begin
			case(addr_io)
				TCNTL_ADDR:
				begin
					if(TCNTL_ADDR < 'h40)
						TMP_REG_rd <= TCNTL;
				end
				ICRL_ADDR:
				begin
					if(ICRL_ADDR < 'h40)
						TMP_REG_rd <= ICRL;
				end
			endcase
		end
		if(rd_dat)
		begin
			case(addr_dat)
				TCNTL_ADDR:
				begin
					if(TCNTL_ADDR >= 'h40)
						TMP_REG_rd <= TCNTL;
				end
				ICRL_ADDR:
				begin
					if(ICRL_ADDR >= 'h40)
						TMP_REG_rd <= ICRL;
				end
			endcase
		end
	end
end

assign tov_int = TIFR[`TOV0];
assign ocra_int = TIFR[`OCF0A];
assign ocrb_int = TIFR[`OCF0B];
assign ocrc_int = TIFR[`OCF0C];
assign ocrd_int = TIFR[`OCF0D];

assign oca_io_connect = (TCCRA[`COM0A1:`COM0A0] == 2'b00) ? 1'b0 : (TCCRA[`COM0A1:`COM0A0] == 2'b01 ? (({TCCRA[`WGM03:`WGM02], TCCRA[`WGM01:`WGM00]} == 4'd14 || {TCCRA[`WGM03:`WGM02], TCCRA[`WGM01:`WGM00]} == 4'd15) ? 1'b1 : 1'b0) : 1'b1);
assign ocb_io_connect = (TCCRA[`COM0B1:`COM0B0] == 2'b00 || TCCRA[`COM0B1:`COM0B0] == 2'b01) ? 1'b0 : 1'b1;
assign occ_io_connect = (TCCRA[`COM0C1:`COM0C0] == 2'b00 || TCCRA[`COM0C1:`COM0C0] == 2'b01) ? 1'b0 : 1'b1;
assign ocd_io_connect = (TCCRA[`COM0D1:`COM0D0] == 2'b00 || TCCRA[`COM0D1:`COM0D0] == 2'b01) ? 1'b0 : 1'b1;

endmodule

