end*/
/* !Sampling implementation */

/* Prescaller selection implementation */
always @ *
begin
	case(TCCRB[`CS02:`CS00])
	3'b001: clk_int = clk;
	3'b010: clk_int = clk8;
	3'b011: clk_int = clk64;
	3'b100: clk_int = clk256;
	3'b101: clk_int = clk1024;
	3'b110: clk_int = t0_fall;
	3'b111: clk_int = t0_rising;
	default: clk_int = 1'b0;
	endcase
end
reg updt_ocr_on_top;
always @ *
begin
	case({TCCRB[`WGM02], TCCRA[`WGM01:`WGM00]})
		3'h0, 3'h2: updt_ocr_on_top = 1'b0;
		default: updt_ocr_on_top = 1'b1;
	endcase
end

reg [7:0]top_value;
always @ *
begin
	case({TCCRB[`WGM02], TCCRA[`WGM01:`WGM00]})
		3'h2, 3'h5, 3'h7: top_value = OCRA_int;
		default: top_value = 8'hff;
	endcase
end

reg [7:0]t_ovf_value;
always @ *
begin
	case({TCCRB[`WGM02], TCCRA[`WGM01:`WGM00]})
		3'd7: t_ovf_value = top_value;
		3'd0, 3'd2, 3'd3: t_ovf_value = 8'hFF;
		default: t_ovf_value = 8'h00;
	endcase
end

// Read registers.
always @ *
begin
	if(rst)
	begin
		bus_io_out = 8'h00;
		bus_dat_out = 8'h00;
	end
	else
	begin
		bus_io_out = 8'h00;
		bus_dat_out = 8'h00;
		if(rd_io)
		begin
			case(addr_io)
				GTCCR_ADDR:
				begin
					bus_io_out = GTCCR;
				end
				TCCRA_ADDR:
				begin
					bus_io_out = TCCRA;
				end
				TCCRB_ADDR:
				begin
					bus_io_out = TCCRB;
				end
				TCNT_ADDR:
				begin
					bus_io_out = TCNT;
				end
				OCRA_ADDR:
				begin
					bus_io_out = OCRA;
				end
				OCRB_ADDR:
				begin
					bus_io_out = OCRB;
				end
